\displaystyle{\begin{aligned}
   {\frac{2}{yx+6}-\frac{4yx}{y^{2}x^{2}-36}} 
      \amp = {\frac{2}{yx+6}}-\frac{4 y x}{(y x+6)(y x-6)} \\
      \amp = \frac{2\cdot({yx-6})}{({yx+6})\cdot({yx-6})} -\frac{4 y x}{(y x+6)(y x-6)} \\
      \amp = \frac{{2\mathopen{}\left(yx-6\right)-4yx}}{(yx+6)(yx-6)} \\
      \amp = \frac{{2yx-12-4yx}}{(yx+6)(yx-6)} \\
      \amp = \frac{{-2yx-12}}{(yx+6)(yx-6)} \\
      \amp = \frac{{-2\mathopen{}\left(yx+6\right)}}{(yx+6)(yx-6)} \\
      \amp = {-\frac{2}{yx-6}}
\end{aligned}
    }
